    static final int MAX = 100005;
    static final double INF = 1e18;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int Q = sc.nextInt();
        int[] a = new int[MAX];
        int[] b = new int[MAX];
        int[] lim = new int[MAX];
        for (int i = 1; i <= n; i++) {
            a[i] = sc.nextInt();
        }
        for (int i = 1; i <= n; i++) {
            b[i] = sc.nextInt();
        }
        for (int i = 1; i <= n; i++) {
            lim[i] = sc.nextInt();
        }
        while (Q-- > 0) {
            int l = sc.nextInt();
            int r = sc.nextInt();
            int g = sc.nextInt();
            double[][] dp = new double[MAX][MAX];
            for (int i = l; i <= r; i++) {
                for (int j = 0; j <= g; j++) {
                    dp[i][j] = INF;
                }
            }
            for (int i = l; i <= r; i++) {
                for (int j = 0; j <= g; j++) {
                    if (j == 0) {
                        dp[i][j] = 0;
                    } else if (i == l) {
                        double cost = a[i] * j + b[i] * j * j;
                        if (j <= lim[i]) {
                            dp[i][j] = cost;
                        }
                    } else {
                        double cost = a[i] * j + b[i] * j * j;
                        if (j <= lim[i]) {
                            dp[i][j] = Math.min(dp[i][j], cost);
                        }
                        for (int k = 0; k <= j; k++) {
                            if (k <= lim[i] && j - k <= lim[i - 1]) {
                                dp[i][j] = Math.min(dp[i][j], dp[i - 1][j - k] + a[i] * k + b[i] * k * k);
                            }
                        }
                    }
                }
            }
            System.out.printf("%.6f\n", dp[r][g]);
        }
    }
}

